head.b:skin:
/*====================================================

Hadoti News Pro
Version : 1.0

====================================================*/


:root{

--primary:#0d6efd;
--secondary:#ff6b00;

--success:#28a745;
--danger:#dc3545;
--warning:#ffc107;

--white:#ffffff;
--black:#111111;

--text:#333333;
--text-light:#666666;

--border:#e5e5e5;
--bg:#f5f5f5;
--card:#ffffff;

--radius:10px;

--shadow:0 5px 20px rgba(0,0,0,.08);

--container:1280px;

--transition:.3s;

}



/*==========================
RESET
==========================*/

*{

margin:0;

padding:0;

box-sizing:border-box;

}

html{

scroll-behavior:smooth;

}

body{

font-family:Arial,Helvetica,sans-serif;

font-size:16px;

background:var(--bg);

color:var(--text);

line-height:1.6;

overflow-x:hidden;

}

img{

max-width:100%;

display:block;

}

a{

text-decoration:none;

color:inherit;

transition:var(--transition);

}

ul{

list-style:none;

}

button,input,textarea{

font:inherit;

outline:none;

border:none;

}

.container{

width:100%;

max-width:var(--container);

margin:auto;

padding:0 15px;

}
